return (() => {
const DEFAULT_SOURCE_SALES_CHANNEL = 'GROSS1';
const DEFAULT_TAX_DIVISOR = 1.19;
const DEFAULT_NET_PRECISION = 2;
const DEFAULT_SCALE_VALUE = '0';
const MINIMAL_ARTICLE_PROPERTIES = [
  'id',
  'articleNumber',
  'availableForSalesChannels',
  'articlePrices.id',
  'articlePrices.version',
  'articlePrices.currencyId',
  'articlePrices.customerId',
  'articlePrices.description',
  'articlePrices.endDate',
  'articlePrices.price',
  'articlePrices.priceScaleType',
  'articlePrices.priceScaleValue',
  'articlePrices.reductionAdditions',
  'articlePrices.salesChannel',
  'articlePrices.startDate',
];

function toFiniteNumber(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function toDistributionChannelKey(entry) {
  if (typeof entry === 'string') return entry.trim();
  if (entry && typeof entry === 'object' && entry.key !== null && entry.key !== undefined) return String(entry.key).trim();
  return '';
}

function normalizePriceString(value, precision = 5) {
  const parsed = toFiniteNumber(value);
  if (parsed === null) return null;
  const factor = 10 ** precision;
  const rounded = Math.round((parsed || 0) * factor) / factor;
  const fixed = rounded.toFixed(precision);
  return fixed.includes('.') ? fixed.replace(/\.?0+$/, '') : fixed;
}

function normalizeScaleValue(value) {
  const parsed = normalizePriceString(value === null || value === undefined ? DEFAULT_SCALE_VALUE : value, 5);
  return parsed === null ? DEFAULT_SCALE_VALUE : parsed;
}

function quoteFilterString(value) {
  const stringValue = String(value ?? '');
  return `"${stringValue.replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`;
}

function buildCurrentTierZeroPredicate({ salesChannel, effectiveTimestamp }) {
  return [
    `(salesChannel = ${quoteFilterString(salesChannel)})`,
    '(customerId null)',
    '(priceScaleValue = 0)',
    `((startDate null) or (startDate <= ${Number(effectiveTimestamp)}))`,
    `((endDate null) or (endDate >= ${Number(effectiveTimestamp)}))`,
    '(priceScaleType = "SCALE_FROM")',
  ].join(' and ');
}

function normalizeStringList(value) {
  if (Array.isArray(value)) return value.map(e => String(e || '').trim()).filter(Boolean);
  if (value === null || value === undefined || value === '') return [];
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      if (Array.isArray(parsed)) return parsed.map(e => String(e || '').trim()).filter(Boolean);
    } catch (_) {}
    return value.split(',').map(e => String(e || '').trim()).filter(Boolean);
  }
  return [String(value).trim()].filter(Boolean);
}

function buildTargetChannels(activeSalesChannels, sourceSalesChannel) {
  const output = { gross: [], net: [] };
  const seen = new Set();
  for (const entry of activeSalesChannels) {
    const key = toDistributionChannelKey(entry);
    if (!key || key === sourceSalesChannel || seen.has(key)) continue;
    seen.add(key);
    if (key.startsWith('GROSS')) output.gross.push(key);
    else if (key.startsWith('NET')) output.net.push(key);
  }
  return output;
}

const activeSalesChannels = $('weclapp GET salesChannel activeSalesChannels').first().json.result || [];
const constants = $('Constants').first().json;
const sourceSalesChannel = constants.sourceSalesChannel || DEFAULT_SOURCE_SALES_CHANNEL;
const effectiveTimestamp = constants.effectiveTimestamp;

const targetChannels = buildTargetChannels(activeSalesChannels, sourceSalesChannel);

const sourcePredicate = buildCurrentTierZeroPredicate({ salesChannel: sourceSalesChannel, effectiveTimestamp });
const articlePriceFieldRef = `articlePrices[${sourcePredicate}].salesChannel`;

const filterClauses = [
  `(${articlePriceFieldRef} = ${quoteFilterString(sourceSalesChannel)})`,
];

const scopedArticleNumbers = normalizeStringList(constants.requestedArticleNumbers);
if (scopedArticleNumbers.length > 0) {
  filterClauses.push(`(articleNumber in [${scopedArticleNumbers.map(n => quoteFilterString(n)).join(', ')}])`);
}

return [{
  json: {
    articleFilter: filterClauses.join(' and '),
    articleProperties: MINIMAL_ARTICLE_PROPERTIES.join(','),
    targetChannels,
    scopedArticleNumbers,
    effectiveTimestamp,
  },
  pairedItem: { item: 0 },
}];
})();

return (() => {
// ── helpers (same as LIVE workflow, kept canonical) ─────────────────────────
const DEFAULT_SOURCE_SALES_CHANNEL = 'GROSS1';
const DEFAULT_TAX_DIVISOR = 1.19;
const DEFAULT_NET_PRECISION = 2;
const DEFAULT_SCALE_VALUE = '0';
const WRITEABLE_PRICE_KEYS = [
  'id', 'version', 'currencyId', 'customerId', 'description', 'endDate',
  'price', 'priceScaleType', 'priceScaleValue', 'reductionAdditions',
  'salesChannel', 'startDate',
];

function toFiniteNumber(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}
function toDistributionChannelKey(entry) {
  if (typeof entry === 'string') return entry.trim();
  if (entry && typeof entry === 'object' && entry.key != null) return String(entry.key).trim();
  return '';
}
function roundToPrecision(value, precision) {
  const factor = 10 ** precision;
  return Math.round((Number(value) || 0) * factor) / factor;
}
function normalizePriceString(value, precision = 5) {
  const parsed = toFiniteNumber(value);
  if (parsed === null) return null;
  const factor = 10 ** precision;
  const rounded = Math.round((parsed || 0) * factor) / factor;
  const fixed = rounded.toFixed(precision);
  return fixed.includes('.') ? fixed.replace(/\.?0+$/, '') : fixed;
}
function normalizeScaleValue(value) {
  const parsed = normalizePriceString(value == null ? DEFAULT_SCALE_VALUE : value, 5);
  return parsed === null ? DEFAULT_SCALE_VALUE : parsed;
}
function isGeneralTierZeroPrice(row) {
  if (!row || (row.customerId !== null && row.customerId !== undefined && row.customerId !== '')) return false;
  return normalizeScaleValue(row.priceScaleValue) === DEFAULT_SCALE_VALUE;
}
function isCurrentAt(row, ts) {
  const s = toFiniteNumber(row.startDate);
  const e = toFiniteNumber(row.endDate);
  return (s === null ? true : s <= ts) && (e === null ? true : e >= ts);
}

function buildTargetChannels(article, activeSalesChannels, sourceSalesChannel) {
  const out = { gross: [], net: [] };
  const seen = new Set();
  const avail = Array.isArray(article.availableForSalesChannels)
    ? new Set(article.availableForSalesChannels.map(String))
    : null;
  for (const entry of activeSalesChannels) {
    const key = toDistributionChannelKey(entry);
    if (!key || key === sourceSalesChannel || seen.has(key)) continue;
    seen.add(key);
    if (avail && avail.size > 0 && !avail.has(key)) continue;
    if (key.startsWith('GROSS')) out.gross.push(key);
    else if (key.startsWith('NET')) out.net.push(key);
  }
  return out;
}

function applyChannelRule(basePrice, channel, channelRules) {
  const rule = channelRules[channel];
  if (!rule) return basePrice;
  let price = basePrice;
  if (typeof rule.percentAdd === 'number' && rule.percentAdd !== 0) price *= (1 + rule.percentAdd / 100);
  if (typeof rule.add === 'number' && rule.add !== 0) price += rule.add;
  return price;
}

// ── Main logic ───────────────────────────────────────────────────────────────
// Output: one item per (articleId, targetChannel) for shouldUpdate=true articles.
// Each item carries: articleId, articleNumber, salesChannel, grossPrice, currencyId,
// validFrom, dryRun — exactly what the weclapp updatePrices node needs.

const articles = $input.all();
const activeSalesChannels = $('weclapp GET salesChannel activeSalesChannels').first().json.result || [];
const constants = $('Constants').first().json;
const sourceSalesChannel = constants.sourceSalesChannel || DEFAULT_SOURCE_SALES_CHANNEL;
const taxDivisor = constants.taxDivisor || DEFAULT_TAX_DIVISOR;
const netPrecision = constants.netPrecision || DEFAULT_NET_PRECISION;
const channelRules = constants.channelRules || {};
const effectiveTimestamp = constants.effectiveTimestamp;
const dryRun = constants.dryRun === true;

const channelItems = [];
const skipped = [];
const errors = [];

for (let i = 0; i < articles.length; i++) {
  const article = articles[i].json;
  try {
    const articlePrices = Array.isArray(article.articlePrices) ? article.articlePrices : [];
    const sourceRows = articlePrices.filter(
      row => row.salesChannel === sourceSalesChannel && isGeneralTierZeroPrice(row) && isCurrentAt(row, effectiveTimestamp)
    );

    if (sourceRows.length === 0) {
      skipped.push({ articleId: article.id, articleNumber: article.articleNumber, status: 'skipped_missing_source_price' });
      continue;
    }
    if (sourceRows.length > 1) {
      skipped.push({ articleId: article.id, articleNumber: article.articleNumber, status: 'skipped_ambiguous_source_price' });
      continue;
    }
    const sourceRow = sourceRows[0];
    const sourcePrice = Number(sourceRow.price);
    const currencyId = String(sourceRow.currencyId || '');

    const targetChannels = buildTargetChannels(article, activeSalesChannels, sourceSalesChannel);
    const allTargetChannels = [...targetChannels.gross, ...targetChannels.net];
    if (allTargetChannels.length === 0) {
      skipped.push({ articleId: article.id, articleNumber: article.articleNumber, status: 'noop_no_target_channels' });
      continue;
    }

    // Gross channels
    for (const channel of targetChannels.gross) {
      const rule = channelRules[channel];
      let grossDesired;
      if (rule && typeof rule.grossTaxMultiplier === 'number') {
        const netBase = sourcePrice / taxDivisor;
        grossDesired = roundToPrecision(applyChannelRule(netBase, channel, channelRules) * rule.grossTaxMultiplier, netPrecision);
      } else if (rule) {
        grossDesired = roundToPrecision(applyChannelRule(sourcePrice, channel, channelRules), netPrecision);
      } else {
        grossDesired = sourcePrice;
      }
      channelItems.push({
        json: {
          articleId: article.id,
          articleNumber: article.articleNumber,
          salesChannel: channel,
          grossPrice: grossDesired,
          currencyId,
          validFrom: effectiveTimestamp,
          dryRun,
          sourcePrice: normalizePriceString(sourcePrice, 5),
        },
        pairedItem: { item: i },
      });
    }

    // Net channels
    for (const channel of targetChannels.net) {
      const netBase = sourcePrice / taxDivisor;
      const netDesired = roundToPrecision(applyChannelRule(netBase, channel, channelRules), netPrecision);
      channelItems.push({
        json: {
          articleId: article.id,
          articleNumber: article.articleNumber,
          salesChannel: channel,
          grossPrice: netDesired,
          currencyId,
          validFrom: effectiveTimestamp,
          dryRun,
          sourcePrice: normalizePriceString(sourcePrice, 5),
        },
        pairedItem: { item: i },
      });
    }
  } catch (err) {
    errors.push({ articleId: article.id, articleNumber: article.articleNumber, error: err.message });
  }
}

if (channelItems.length === 0) {
  return [{
    json: {
      __summaryOnly: true,
      totalArticles: articles.length,
      skipped,
      errors,
      message: 'No articles require price updates',
    },
    pairedItem: { item: 0 },
  }];
}

// Prepend a summary item (won't be processed by updatePrices — guarded by If has updates)
// All real channel items follow.
return channelItems;
})();
